import threading

class Account:
    def __init__(self, balance=0):
        self.balance = balance
        self.lock = threading.Lock()

    def process_transaction(self, amount):
        with self.lock:
            self.balance += amount

    def get_balance(self):
        with self.lock:
            return self.balance

